import machine
import network
import time
import coap
from coap import CoapServer, Resource

# Initialize WiFi
wlan = network.WLAN(network.STA_IF)
wlan.active(True)
wlan.connect('your_ssid', 'your_password')

while not wlan.isconnected():
    time.sleep(1)

# Sensor and actuator resources
class TemperatureResource(Resource):
    def __init__(self):
        super().__init__()
        self.temp = 25.0
    
    def get(self, request):
        return str(self.temp)
    
    def put(self, request):
        self.temp = float(request.payload)
        return "Temperature updated"

class LightResource(Resource):
    def __init__(self):
        super().__init__()
        self.light = 0
    
    def get(self, request):
        return str(self.light)
    
    def put(self, request):
        self.light = int(request.payload)
        return "Light updated"

# Create server
server = CoapServer()

# Add resources
server.add_resource('/sensors/temp', TemperatureResource())
server.add_resource('/actuators/light', LightResource())

# Start server
try:
    server.start()
    print("CoAP Server started")
    while True:
        server.handle_request()
        time.sleep(0.01)
except KeyboardInterrupt:
    server.stop()
    print("Server stopped")